      "content": "const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');

function addTask(projectId, taskData) {
  const project = projectsService.getProjectById(projectId);
  if (!project) return null;
  const task = { id: randomUUID(), ...taskData, comments: [] };
  project.tasks.push(task);
  return task;
}

function updateTask(projectId, taskId, updates) {
  const project = projectsService.getProjectById(projectId);
  if (!project) return null;
  const taskIndex = project.tasks.findIndex(t => t.id === taskId);
  if (taskIndex === -1) return null;
  const updatedTask = { ...project.tasks[taskIndex], ...updates };
  project.tasks[taskIndex] = updatedTask;
  return updatedTask;
}

function getTasksByProjectId(projectId) {
  const project = projectsService.getProjectById(projectId);
  return project ? project.tasks : [];
}

module.exports = {
  addTask,
  updateTask,
  getTasksByProjectId,
};
